import React, { useState, useCallback, useRef } from 'react';
import { DataTable } from 'primereact/datatable';
import { Column } from 'primereact/column';
import { InputText } from 'primereact/inputtext';
import { InputNumber } from 'primereact/inputnumber';
import { Button } from 'primereact/button';
import { Card } from 'primereact/card';
import { Tag } from 'primereact/tag';
import { Toast } from 'primereact/toast';
import { openAccount, getAccountsByClient, closeAccount } from '../api';
import { BankAccount } from '../types';
import './AccountsPage.css';

const AccountsPage: React.FC = () => {
  const toast = useRef<Toast>(null);

  // ── Open account form ─────────────────────────────────────────────────────
  const [clientId, setClientId] = useState<number | null>(null);
  const [iban, setIban] = useState('');
  const [opening, setOpening] = useState(false);

  // ── Search ────────────────────────────────────────────────────────────────
  const [searchId, setSearchId] = useState<number | null>(null);
  const [accounts, setAccounts] = useState<BankAccount[]>([]);
  const [searching, setSearching] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [closingId, setClosingId] = useState<number | null>(null);

  const loadAccounts = useCallback(async (id: number) => {
    setSearching(true);
    try {
      setAccounts(await getAccountsByClient(id));
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
      setAccounts([]);
    } finally {
      setSearching(false);
    }
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchId || searchId <= 0) {
      toast.current?.show({ severity: 'warn', summary: 'Validation', detail: 'Enter a valid Client ID.' });
      return;
    }
    setHasSearched(true);
    await loadAccounts(searchId);
  };

  const handleOpen = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!clientId || clientId <= 0 || !iban.trim()) {
      toast.current?.show({ severity: 'warn', summary: 'Validation', detail: 'Client ID and IBAN are required.' });
      return;
    }
    setOpening(true);
    try {
      const acc = await openAccount({ clientId, iban: iban.trim() });
      toast.current?.show({ severity: 'success', summary: 'Opened', detail: `Account ${acc.iban} opened successfully.` });
      setClientId(null);
      setIban('');
      if (searchId === clientId) await loadAccounts(clientId);
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setOpening(false);
    }
  };

  const handleClose = async (acc: BankAccount) => {
    setClosingId(acc.id);
    try {
      await closeAccount(acc.id);
      if (searchId) await loadAccounts(searchId);
      toast.current?.show({ severity: 'success', summary: 'Closed', detail: `Account ${acc.iban} closed.` });
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setClosingId(null);
    }
  };

  const statusBody = (row: BankAccount) => (
    <Tag value={row.status} severity={row.status === 'ACTIVE' ? 'success' : 'danger'} />
  );

  const balanceBody = (row: BankAccount) => (
    <span className="ap-balance">BGN {row.balance.toFixed(2)}</span>
  );

  const actionBody = (row: BankAccount) => (
    <Button
      label="Close Account"
      icon="pi pi-times-circle"
      size="small"
      severity="danger"
      outlined
      disabled={row.status === 'CLOSED' || closingId === row.id}
      loading={closingId === row.id}
      onClick={() => handleClose(row)}
    />
  );

  return (
    <div className="ap-page">
      <Toast ref={toast} />
      <div className="ap-page-header">
        <h1 className="ap-page-title">Accounts</h1>
        <p className="ap-page-subtitle">Open, manage and close bank accounts</p>
      </div>

      <div className="ap-top-grid">
        {/* Open account form */}
        <Card title="Open New Account" className="ap-card">
          <form className="ap-form" onSubmit={handleOpen}>
            <div className="ap-field">
              <label>Client ID</label>
              <InputNumber
                value={clientId}
                onValueChange={(e) => setClientId(e.value ?? null)}
                placeholder="e.g. 1"
                min={1}
                disabled={opening}
                useGrouping={false}
              />
            </div>
            <div className="ap-field">
              <label>IBAN</label>
              <InputText
                value={iban}
                onChange={(e) => setIban(e.target.value)}
                placeholder="e.g. BG80BNBG96611020345678"
                disabled={opening}
              />
            </div>
            <Button
              type="submit"
              label="Open Account"
              icon="pi pi-plus"
              loading={opening}
              className="ap-submit-btn"
            />
          </form>
        </Card>

        {/* Search form */}
        <Card title="Find Accounts by Client" className="ap-card">
          <form className="ap-search-form" onSubmit={handleSearch}>
            <div className="ap-field">
              <label>Client ID</label>
              <InputNumber
                value={searchId}
                onValueChange={(e) => setSearchId(e.value ?? null)}
                placeholder="Enter Client ID"
                min={1}
                disabled={searching}
                useGrouping={false}
              />
            </div>
            <Button
              type="submit"
              label="Load Accounts"
              icon="pi pi-search"
              loading={searching}
              className="ap-submit-btn"
            />
          </form>
        </Card>
      </div>

      {hasSearched && (
        <Card
          title={`Accounts — Client #${searchId}`}
          className="ap-results-card"
        >
          <DataTable
            value={accounts}
            loading={searching}
            stripedRows
            paginator
            rows={10}
            emptyMessage="No accounts found for this client."
            rowClassName={(row: BankAccount) => ({ 'ap-row-closed': row.status === 'CLOSED' })}
          >
            <Column field="id" header="ID" style={{ width: 70 }} body={(r) => `#${r.id}`} sortable />
            <Column field="iban" header="IBAN" />
            <Column header="Balance" body={balanceBody} sortable field="balance" />
            <Column header="Status" body={statusBody} style={{ width: 110 }} />
            <Column header="Actions" body={actionBody} style={{ width: 160 }} />
          </DataTable>
        </Card>
      )}
    </div>
  );
};

export default AccountsPage;
